import{_ as e,o as t,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"G11: 前十大客戶與供應商穩定度 - finance-investment-researcher 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/8064_東捷/20260429/G11_前十大客戶與供應商穩定度_投資研究員.md","filePath":"審計報告庫/經營審計/8064_東捷/20260429/G11_前十大客戶與供應商穩定度_投資研究員.md"}'),n={name:"審計報告庫/經營審計/8064_東捷/20260429/G11_前十大客戶與供應商穩定度_投資研究員.md"};function o(l,a,s,c,h,_){return t(),r("div",null,[...a[0]||(a[0]=[i('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的投資洞見。</p><h1 id="g11-前十大客戶與供應商穩定度-finance-investment-researcher-審計報告" tabindex="-1">G11: 前十大客戶與供應商穩定度 - finance-investment-researcher 審計報告 <a class="header-anchor" href="#g11-前十大客戶與供應商穩定度-finance-investment-researcher-審計報告" aria-label="Permalink to &quot;G11: 前十大客戶與供應商穩定度 - finance-investment-researcher 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>近三年中，前十大客戶與供應商變動情形為何？客戶集中度風險是否正在惡化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：Top 1 佔比 35%→15%，Top 3 合計 46%→28%，集中度顯著分散，但個別大客戶掉單衝擊仍強。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：截至2025年合併財務報告</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>客戶 A 35%→36%（112年最高）→15%；客戶 B 11%→1%→11%；客戶 C 12%→2%（114年降至第三）；Top 3 合計 46%→49%→28%；總營收 $29.9億→$27.5億→$28.7億</li></ul></li><li><strong>診斷見解</strong>：Top 3 佔比腰斬至 28%，分散化改善顯著；客戶 A 112年佔比35%創最高，114年降至15%為主動分散成果；客戶 B 歸零後恢復但金額仍低7%；客戶 C 114年滑落至第三。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、客戶集中度趨勢-從高度集中到結構分散" tabindex="-1">一、客戶集中度趨勢：從高度集中到結構分散 <a class="header-anchor" href="#一、客戶集中度趨勢-從高度集中到結構分散" aria-label="Permalink to &quot;一、客戶集中度趨勢：從高度集中到結構分散&quot;">​</a></h3><ul><li><strong>核心重點</strong>：Top 1 客戶 A 佔比由 35%→36%→15%，Top 3 合計由 46%→49%→28%。</li><li><strong>深度見解</strong>：集中度呈「先升後降」U 型走勢。113 年因營收下滑（$29.9億→$27.5億），客戶 A 佔比反升，屬被動集中。114 年營收回升至 $28.7億，客戶 A 金額大幅縮減（$9.47億→$4.19億），主動分散奏效。客戶 B 113 年幾乎消失（1%），114 年恢復至 11%，但金額較 112 年仍低 7%。客戶 C 113 年躍升第二大（$3.10億，12%），114 年降至 $0.59億（2%）。此消彼長，反映東捷正處客戶結構重組期。</li></ul><h3 id="三、供應商穩定度-資料不足-待補充" tabindex="-1">三、供應商穩定度：資料不足，待補充 <a class="header-anchor" href="#三、供應商穩定度-資料不足-待補充" aria-label="Permalink to &quot;三、供應商穩定度：資料不足，待補充&quot;">​</a></h3><ul><li><strong>核心重點</strong>：合併財務報告未揭露前十大供應商。僅關係人進貨金額極低（114年合計 $2.07億）。</li><li><strong>深度見解</strong>：供應鏈集中風險無法從現有財報量化。東捷供應商涵蓋盟立（2464）、由田（3455）、晶彩科（3535）、旭東（4537）、廣運（6125）及國際廠 Lasertec、Kubotek 等，基礎看似多元。但缺乏具體採購佔比數據，無法執行供應鏈集中度評分。建議查閱 114 年度股東會年報「主要供銷貨客戶名單」取得完整資訊。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><p><strong>空頭風險一：客戶 B 型掉單事件可能重演。</strong> 113 年客戶 B 營收貢獻從 $3.26億暴跌至 $0.24億（降幅 93%）。若半導體大客戶資本支出放緩，東捷可能面臨類似掉單危機。Top 1 客戶 A 佔比雖降至 15%，絕對金額 $4.19億仍具規模，一旦重演客戶 B 式掉單，營收將遭受雙重打擊。</p></li><li><p><strong>空頭風險二：供應商集中風險隱而未現。</strong> 合併財務報告未揭露前十大供應商資訊，供應鏈集中度處於黑箱。東捷核心零組件（雷射模組、AOI 光學系統、真空設備）可能高度依賴少數國際供應商。若關鍵零組件供應中斷或漲價，公司毛利將直接受壓。東捷透過私募引入志聖（2464）持股 10.82%，此策略合作可能導致供應商關係過度綁定單一集團生態系。</p></li><li><p><strong>空頭風險三：Micro LED 量產時程不確定性。</strong> 公司將 Micro LED 列為核心成長動能，但終端品牌商的量產決策反覆不定。若量產延遲或轉向其他顯示技術，東捷研發投資將無法如期變現。114 年客戶 C（可能為 Micro LED 相關）營收貢獻從 12% 暴跌至 2%，暗示新市場拓展面臨瓶頸。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: 未執行（本題以年報財務報告為主體，FinMind alias 適用性有限）</li><li><strong>yfinance</strong>: 未執行（非上市櫃股票，無公開股價數據需求）</li><li><strong>年報/財報</strong>: OK — 東捷科技 112/113/114 年度合併財務報告（PDF），主要客戶資訊分別位於各報告第 69-71 頁「(五) 主要客戶資訊」 <ul><li>關鍵核對碼：112年客戶A $1,056,049仟（35%）、113年客戶A $947,373仟（36%）、114年客戶A $419,172仟（15%）</li></ul></li><li><strong>外部搜尋</strong>: OK — 東捷科技客戶涵蓋群創光電、台積電；供應商含盟立（2464）、由田（3455）、晶彩科（3535）等；2025年總營收 $28.71億，Q4 單季年增 75.95%</li><li><strong>關鍵核對碼</strong>：114年客戶A $419,172仟（15%）+ 客戶B $303,451仟（11%）+ 客戶C $58,610仟（2%）= Top 3 合計 $781,233仟</li></ul><hr><p><strong>審計執行日</strong>：2026-04-29 <strong>數據基準</strong>：民國 112~114 年度（2023~2025）合併財務報告 <strong>評級結論</strong>：客戶集中度風險「可控但波動劇烈」，結構分散化改善顯著，但個別大客戶掉單衝擊仍具破壞性。</p>',19)])])}const u=e(n,[["render",o]]);export{g as __pageData,u as default};
